class MultiSig:
    def __init__(self):
        self.proposals = {} # id -> proposal details

    def propose(self, proposal_id, action_payload, required_sigs):
        if proposal_id not in self.proposals:
            self.proposals[proposal_id] = {
                "payload": action_payload,
                "required": required_sigs,
                "signatures": [],
                "executed": False
            }
        return True

    def approve(self, proposal_id, address_sig):
        if proposal_id in self.proposals:
            prop = self.proposals[proposal_id]
            if address_sig not in prop["signatures"]:
                prop["signatures"].append(address_sig)
        return True

    def execute(self, proposal_id):
        prop = self.proposals.get(proposal_id)
        if prop and len(prop["signatures"]) >= prop["required"] and not prop["executed"]:
            prop["executed"] = True
            return True
        raise Exception("Not ready for execution")

class CertificateAuthority:
    def __init__(self):
        self.certs = {}
        self.revoked = []

    def issueCert(self, cert_id, subject_data):
        self.certs[cert_id] = subject_data
        return True

    def revokeCert(self, cert_id):
        if cert_id not in self.revoked:
            self.revoked.append(cert_id)
        return True

    def verifyCert(self, cert_id):
        return cert_id in self.certs and cert_id not in self.revoked

class AccessControl:
    def __init__(self):
        # Maps user_id -> list of roles e.g., ["ISSUER", "VERIFIER"]
        self.roles = {}
        # Simple admin identity
        self.admin = "system_admin"

        # Pre-populate admin
        self.roles[self.admin] = ["ADMIN"]

    def grant_role(self, caller: str, user_id: str, role: str) -> dict:
        """Grants a role to a user. Only an ADMIN can grant roles."""
        caller_roles = self.roles.get(caller, [])
        if "ADMIN" not in caller_roles and caller != self.admin:
            return {"error": "Unauthorized: Only ADMIN can grant roles"}

        if user_id not in self.roles:
            self.roles[user_id] = []

        role_upper = role.upper()
        if role_upper not in self.roles[user_id]:
            self.roles[user_id].append(role_upper)

        return {"status": "success", "message": f"Role {role_upper} granted to {user_id}"}

    def revoke_role(self, caller: str, user_id: str, role: str) -> dict:
        """Revokes a role from a user. Only an ADMIN can revoke roles."""
        caller_roles = self.roles.get(caller, [])
        if "ADMIN" not in caller_roles and caller != self.admin:
            return {"error": "Unauthorized: Only ADMIN can revoke roles"}

        role_upper = role.upper()
        if user_id in self.roles and role_upper in self.roles[user_id]:
            self.roles[user_id].remove(role_upper)
            return {"status": "success", "message": f"Role {role_upper} revoked from {user_id}"}

        return {"error": "User does not have this role"}

    def has_role(self, caller: str, user_id: str, role: str) -> dict:
        """Checks if a user has a specific role. Anyone can check roles."""
        role_upper = role.upper()
        user_roles = self.roles.get(user_id, [])

        has_it = role_upper in user_roles
        return {"status": "success", "has_role": has_it, "roles": user_roles}

    def get_all_roles(self, caller: str, user_id: str) -> dict:
        """Returns all roles for a given user."""
        return {"status": "success", "roles": self.roles.get(user_id, [])}

class  CertificateRegistry:
    def __init__(self):
        # Maps cert_id -> { 'student_name': str, 'degree': str, 'year': int, 'issuer_id': str, 'is_revoked': bool }
        self.certificates = {}

    def issue_certificate(self, caller: str, cert_id: str, student_name: str, degree: str, year: int, issuer_id: str) -> dict:
        """
        Issues a new certificate. 
        Note: The FastAPI backend MUST verify that 'issuer_id' has the 'ISSUER' role 
        via the AccessControl contract before calling this method.
        """
        if cert_id in self.certificates:
            return {"error": "Certificate ID already exists"}

        self.certificates[cert_id] = {
            "student_name": student_name,
            "degree": degree,
            "year": year,
            "issuer_id": issuer_id,
            "is_revoked": False
        }

        return {"status": "success", "cert_id": cert_id}

    def revoke_certificate(self, caller: str, cert_id: str, requester_id: str) -> dict:
        """
        Revokes a certificate. 
        The requester_id must be the original issuer or an authorized party.
        """
        if cert_id not in self.certificates:
            return {"error": "Certificate not found"}

        cert = self.certificates[cert_id]

        # Only the original issuer can revoke it
        if cert["issuer_id"] != requester_id:
            return {"error": "Unauthorized: Only the original issuer can revoke this certificate"}

        if cert["is_revoked"]:
            return {"error": "Certificate is already revoked"}

        cert["is_revoked"] = True
        return {"status": "success", "message": "Certificate revoked"}

    def verify_certificate(self, caller: str, cert_id: str) -> dict:
        """Verifies if a certificate is valid and not revoked."""
        if cert_id not in self.certificates:
            return {"status": "not_found", "is_valid": False}

        cert = self.certificates[cert_id]
        if cert["is_revoked"]:
            return {"status": "revoked", "is_valid": False}

        return {"status": "valid", "is_valid": True}

    def get_certificate(self, caller: str, cert_id: str) -> dict:
        """Returns the full details of a certificate."""
        if cert_id not in self.certificates:
            return {"error": "Certificate not found"}

        return {"status": "success", "data": self.certificates[cert_id]}
